return items
  .map(item => {
    const demandDate = new Date(item.json.FKDAT);
    const paymentDate = new Date(item.json.PAY_DATE);

    const diffDays = (paymentDate - demandDate) / (1000 * 60 * 60 * 24);

    if (diffDays >= 0 && diffDays <= 5) {
      return {
        json: {
          customer_id: item.json.KUNNR,
          demand_date: item.json.FKDAT,
          payment_date: item.json.PAY_DATE,
          diff_days: diffDays,
          points: 6000,
          rule: "Paid within 5 days"
        }
      };
    }

    return null;
  })
  .filter(Boolean);

return items.map(item => {

  return {
    json: {
      customer_code: item.json.Customer_No__c,
      CreditedById: item.json.CreatedById,
      mobile_number: item.json.MobilePhone,
      amount: 1000,
      transaction_type: "CREDIT",
      remarks: "Referral Points",
      transaction_note: "Referral reward",
      payment_mode: "cash",
      topup_by: "automation",
      lead_id: item.json.Lead_Id__c,
      created_at: new Date().toISOString()
    }
  };

});

return items.map(item => {

  const accountMobile =
    item.json.Account_Mobile_Number__c ||
    item.json.Account_Mobile_1__c ||
    null;

  return {
    json: {
      customer_code: item.json.Customer_No__c,
      id: item.json.ID,
      lead_id: item.json.Lead_Id__c,

      customer_mobile: accountMobile,
      reference_id: accountMobile,

      amount: 1000,
      transaction_type: "CREDIT",
      remarks: "Referral Points Site Visit Done",
      transaction_note: "site_visit_loyalty_reward",
      payment_mode: "cash",
      topup_by: "automation",

      stage: item.json.StageName,
      lead_source: item.json.LeadSource,
      project: item.json.Project_Name,

      credited_on: item.json.SV_Date__c,

      created_at: new Date().toISOString()
    }
  };

});

return items.map(item => {

  const mobile =
    item.json.Account_Mobile_Number__c ||
    item.json.Account_Mobile_1__c ||
    item.json.Mobile_Number__c ||
    null;

  return {
    json: {
      customer_code: item.json.ID,
      leadId: item.json.Lead_Id__c,
      opportunityId: item.json.Opportunity_ID__c,

      // unified mobile (future unique constraint)
      customerMobile: mobile,

      email: item.json.Email_Address__c,
      customerName: item.json.Name,

      amount: 1000,
      remarks: "Referral Points",
      transaction_note: "Points credited for referral Booking Confirmation",
      payment_mode: "cash",
      topup_by: "automation",

      leadSource: item.json.LeadSource,
      stage: item.json.StageName,

      createdAt: new Date().toISOString()
    }
  };
});
